// Items in a 'CustomerOrders' table with composite key (PK=CustomerId, SK=OrderDate).
// Same PK => same partition, sorted by SK, so range queries are cheap.
{ "CustomerId": "CUST#42", "OrderDate": "2026-01-05", "Total": 1999, "Status": "SHIPPED" }
{ "CustomerId": "CUST#42", "OrderDate": "2026-02-11", "Total": 4500, "Status": "PLACED" }
{ "CustomerId": "CUST#42", "OrderDate": "2026-03-02", "Total":  799, "Status": "PLACED" }

// Query: 'orders for CUST#42 in Q1 2026' -> one partition, sorted range scan.
// KeyConditionExpression:
//   CustomerId = :c AND OrderDate BETWEEN :start AND :end

// Single-table design: users, their orders, and order items in ONE table.
// Generic keys PK/SK; entity type encoded in the key prefix.
{ "PK": "USER#42",    "SK": "PROFILE#",        "name": "Ada", "email": "ada@x.com" }
{ "PK": "USER#42",    "SK": "ORDER#2026-03-02", "orderId": "O#900", "total": 799 }
{ "PK": "USER#42",    "SK": "ORDER#2026-02-11", "orderId": "O#812", "total": 4500 }
{ "PK": "ORDER#900",  "SK": "ITEM#1",           "sku": "ABC", "qty": 2 }
{ "PK": "ORDER#900",  "SK": "ITEM#2",           "sku": "XYZ", "qty": 1 }

// Access pattern 'get user + all their orders' = ONE query:
//   PK = USER#42  (returns the PROFILE item and all ORDER# items together)
// Access pattern 'get an order's line items' = ONE query:
//   PK = ORDER#900 AND begins_with(SK, 'ITEM#')

// GOOD: Query a single partition by key condition.
await ddb.query({
  TableName: 'CustomerOrders',
  KeyConditionExpression: 'CustomerId = :c AND begins_with(OrderDate, :y)',
  ExpressionAttributeValues: { ':c': 'CUST#42', ':y': '2026' }
}); // reads only CUST#42's 2026 orders

// BAD: Scan the whole table and filter -> reads (and bills) the ENTIRE table.
await ddb.scan({
  TableName: 'CustomerOrders',
  FilterExpression: 'CustomerId = :c',
  ExpressionAttributeValues: { ':c': 'CUST#42' }
}); // a filter is NOT an index; capacity consumed scales with table size

