// ---------- TABLE: 'Commerce' ----------
// Primary key: PK (partition), SK (sort). Entity type encoded in key prefixes.
// GSI1: PK = GSI1PK, SK = GSI1SK  (for status-based, recency-sorted queries)

// ----- Items -----
// User profile (lives under the user's partition)
{ "PK": "USER#42", "SK": "PROFILE#",          "type": "User",  "name": "Ada", "email": "ada@x.com" }

// Orders for a user (same partition as the user => fetched together)
{ "PK": "USER#42", "SK": "ORDER#2026-03-02#O900", "type": "Order", "orderId": "O900", "status": "PLACED",  "total": 799,
  "GSI1PK": "STATUS#PLACED",  "GSI1SK": "2026-03-02T10:00:00Z#O900" }
{ "PK": "USER#42", "SK": "ORDER#2026-02-11#O812", "type": "Order", "orderId": "O812", "status": "SHIPPED", "total": 4500,
  "GSI1PK": "STATUS#SHIPPED", "GSI1SK": "2026-02-11T09:00:00Z#O812" }

// Line items for an order (their OWN partition keyed by order id)
{ "PK": "ORDER#O900", "SK": "ITEM#1", "type": "OrderItem", "sku": "ABC", "qty": 2, "price": 300 }
{ "PK": "ORDER#O900", "SK": "ITEM#2", "type": "OrderItem", "sku": "XYZ", "qty": 1, "price": 199 }

// ----- Access patterns -----

// (1) Get a user's profile -> GetItem on the exact key.
{ "op": "GetItem", "Key": { "PK": "USER#42", "SK": "PROFILE#" } }

// (2) Get user profile + ALL their orders in ONE request.
//     Same partition (USER#42); SK begins_with selects profile+orders.
{ "op": "Query",
  "KeyConditionExpression": "PK = :pk",
  "ExpressionAttributeValues": { ":pk": "USER#42" } }
// (returns PROFILE# and every ORDER#... item for that user, sorted by SK)

// (3) Get all line items for an order.
{ "op": "Query",
  "KeyConditionExpression": "PK = :pk AND begins_with(SK, :p)",
  "ExpressionAttributeValues": { ":pk": "ORDER#O900", ":p": "ITEM#" } }

// (4) List all orders with a given status, NEWEST FIRST -> GSI1.
//     GSI1PK groups by status; GSI1SK is an ISO timestamp so sorting works;
//     ScanIndexForward=false gives descending (newest first).
{ "op": "Query", "IndexName": "GSI1",
  "KeyConditionExpression": "GSI1PK = :s",
  "ExpressionAttributeValues": { ":s": "STATUS#PLACED" },
  "ScanIndexForward": false }

// ----- GSI definition (conceptual) -----
// GSI1: partition key = GSI1PK (e.g. STATUS#PLACED), sort key = GSI1SK (timestamp#orderId)
// Note: querying by status this way risks a HOT GSI partition if one status
// dominates; mitigate with status#shardN as GSI1PK and scatter-gather, or by
// time-bucketing (STATUS#PLACED#2026-03).

// ---------- BEFORE (hot partition) ----------
// PK = 'sensor-data' (constant!) , SK = timestamp
// Every write -> the SAME partition -> throttling regardless of table capacity.

// ---------- AFTER (write sharding) ----------
const SHARD_COUNT = 10; // tune to spread load across enough partitions

// Deterministic shard from a stable attribute (device id) so a device's data
// is reproducible; use a random shard if you do not need per-device locality.
function shardFor(deviceId) {
  let h = 0;
  for (const ch of deviceId) h = (h * 31 + ch.charCodeAt(0)) >>> 0;
  return h % SHARD_COUNT; // 0..9
}

async function writeReading(ddb, deviceId, timestamp, value) {
  const shard = shardFor(deviceId);
  await ddb.putItem({
    TableName: 'Telemetry',
    Item: {
      PK: `sensor-data#${shard}`,         // spreads writes across 10 partitions
      SK: `${timestamp}#${deviceId}`,      // sortable; unique within the shard
      deviceId, value,
    },
  });
}

// ---------- READ: scatter-gather across all shards for a time range ----------
async function readRange(ddb, startTs, endTs) {
  const queries = [];
  for (let shard = 0; shard < SHARD_COUNT; shard++) {
    queries.push(ddb.query({
      TableName: 'Telemetry',
      KeyConditionExpression: 'PK = :pk AND SK BETWEEN :s AND :e',
      ExpressionAttributeValues: {
        ':pk': `sensor-data#${shard}`,
        ':s': `${startTs}#`,
        ':e': `${endTs}#\uffff`,           // \uffff makes the range inclusive of all device ids
      },
    }));
  }
  // Run all shard queries in parallel, then merge + sort by timestamp.
  const results = await Promise.all(queries);
  const items = results.flatMap(r => r.Items);
  return items.sort((a, b) => a.SK.localeCompare(b.SK));
}

// If reads are usually per-DEVICE, prefer PK = `device#${deviceId}` instead:
// that gives a high-cardinality key AND single-partition reads per device,
// avoiding scatter-gather entirely. Sharding under a constant prefix is for
// when you must read ACROSS all devices by time.
